2. 
3. namespace TaskManager.Services;
4. 
5. public static class TaskFormatter
6. {
7.     public static string FormatTask(TaskItem task)
8.     {
9.         var status = task.IsCompleted ? "Done" : "Pending";
10.         var assignee = task.AssignedTo ?? "Unassigned";
11.         var due = task.DueDate.HasValue
12.             ? task.DueDate.Value.ToShortDateString()
13.             : "No due date";
14.         return $"[{status}] {task.Title} - {assignee} (Due: {due})";
15.     }
16. 
17.     public static string FormatProject(Project project)
18.     {
19.         var lines = new List<string>
20.         {
21.             $"Project: {project.Name} (Owner: {project.Owner})",
22.             $"Tasks: {project.Tasks.Count}"
23.         };
24.         foreach (var task in project.Tasks)
25.         {
26.             lines.Add($"  - {FormatTask(task)}");
27.         }
28.         return string.Join(Environment.NewLine, lines);
29.     }
30. }
31.

